FROM jsonb_to_recordset('[{"id": "cap-105-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「考期將至，望著桌上堆積如山的書本，我的心在瞬間彷彿變成了鉛塊。當下只\n有悔恨，悔恨自己未能善加運用時間。」作者在句中以「鉛塊」來比喻他當下\n的哪一種心情？", "options": ["煩躁", "堅定", "麻木", "沉重"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   「考期將至，望著桌上堆積如山的書本，我的心在瞬間彷彿變成了鉛塊。當下只\n     有悔恨，悔恨自己未能善加運用時間。」作者在句中以「鉛塊」來比喻他當下\n     的哪一種心情？\n     (A)煩躁     (B)堅定    (C)麻木     (D)沉重\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「荷馬史詩是永遠的傑作，但不能永遠以它為範本。」這句話的意旨與下列何\n者最接近？", "options": ["敏銳的鑑賞力是創作優良作品的前提", "創作必須求新求進，不能一味地模仿", "再偉大的作品，價值也會隨時間而減損", "作家過度被崇拜時，往往難以自我超越"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   「荷馬史詩是永遠的傑作，但不能永遠以它為範本。」這句話的意旨與下列何\n     者最接近？\n     (A)敏銳的鑑賞力是創作優良作品的前提\n     (B)創作必須求新求進，不能一味地模仿\n     (C)再偉大的作品，價值也會隨時間而減損\n     (D)作家過度被崇拜時，往往難以自我超越\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "\u001b\u001a\u0019\n\u0003\u0002\u0005\u0004，\n\u001b\u001a\u0019\u0018\u0017\u0016\u0015        \n\u0010\n\u0014\u0013\u0012\u0011\u0010\u000f\u000e         ­   \u000f\n\b\u0007\u0006\n\u0005\u0004\u001a       \u001b\n\n\n關於這段詩句的解說，下列敘述何者正確？", "options": ["本詩主旨在於藉由鳥類不同的生活型態，比喻人生窮通禍福的境遇", "詩中運用人性化筆法，藉鳥之口控訴人類的貪婪與對待禽鳥的惡行", "詩中的「我」以無私的心態來對待眾鳥，不願以鳥籠圈限鳥的自由", "詩中的「你」獨愛畫眉鳥，遂於鳥店購得一隻，終日描繪牠的形貌"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.\n\n               \u001f\n\n\n\n               \u001f\n\n \n      \u001b\u001a\u0019\n\n       \u001f\u001f\n\n\n          \u0003\u0002\u0005\u0004，\n       \u001b\u001a\u0019\u0018\u0017\u0016\u0015        \n\u0010\n       \u0014\u0013\u0012\u0011\u0010\u000f\u000e         ­   \u000f\n        \b\u0007\u0006\n\u0005\u0004\u001a       \u001b\n                      \n                      \n\n\n     關於這段詩句的解說，下列敘述何者正確？\n     (A)本詩主旨在於藉由鳥類不同的生活型態，比喻人生窮通禍福的境遇\n     (B)詩中運用人性化筆法，藉鳥之口控訴人類的貪婪與對待禽鳥的惡行\n     (C)詩中的「我」以無私的心態來對待眾鳥，不願以鳥籠圈限鳥的自由\n     (D)詩中的「你」獨愛畫眉鳥，遂於鳥店購得一隻，終日描繪牠的形貌\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「我們不是讓自己活得悲慘，就是讓自己活得堅強。兩者所花的力量是一樣的。」\n「命運與機會無關，而是與選擇有關。它不是等著發生的東西，而是等著努力達成的\n東西。」\n這兩句話共同傳達出的涵義，與下列何者最接近？", "options": ["人生方向可由自己掌握", "以堅強的態度接受失敗", "快樂與痛苦是一體兩面", "機會是可遇而不可求的"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 4, "raw_text": "4.   「我們不是讓自己活得悲慘，就是讓自己活得堅強。兩者所花的力量是一樣的。」\n     「命運與機會無關，而是與選擇有關。它不是等著發生的東西，而是等著努力達成的\n     東西。」\n     這兩句話共同傳達出的涵義，與下列何者最接近？\n     (A)人生方向可由自己掌握       (B)以堅強的態度接受失敗\n     (C)快樂與痛苦是一體兩面       (D)機會是可遇而不可求的\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "下列選項「」中的文字，何組讀音相同？", "options": ["為減輕生產痛苦，有些產婦選擇無痛分「娩」／救援投手獨撐全局，力「挽」狂瀾", "你別「呶」呶不休，讓我耳根不得清淨／雙方意見不合，僵持不下，劍拔「弩」張", "坊間「贗」品幾可亂真，小心上當／我們要服「膺」師長的教導，切不可一意孤行", "瞧他「躊」躇滿志的模樣，真令人反感／開放農產品進口，是我方的談判「籌」碼"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.   下列選項「」中的文字，何組讀音相同？\n     (A)為減輕生產痛苦，有些產婦選擇無痛分「娩」／救援投手獨撐全局，力「挽」狂瀾\n     (B)你別「呶」呶不休，讓我耳根不得清淨／雙方意見不合，僵持不下，劍拔「弩」張\n     (C)坊間「贗」品幾可亂真，小心上當／我們要服「膺」師長的教導，切不可一意孤行\n     (D)瞧他「躊」躇滿志的模樣，真令人反感／開放農產品進口，是我方的談判「籌」碼\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「我的作文功力和明華差不多，可以說是□□□□；思恩的表現更好，我只能勉\n強□□□□；而蔚然是作文的常勝軍，和她比的話我就□□□□了！」這段\n文字的空格處，依序應填上哪一組成語？", "options": ["不分軒輊／望塵莫及／望其項背", "不分軒輊／望其項背／望塵莫及", "望其項背／望塵莫及／不分軒輊", "望其項背／不分軒輊／望塵莫及"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.   「我的作文功力和明華差不多，可以說是□□□□；思恩的表現更好，我只能勉\n     強□□□□；而蔚然是作文的常勝軍，和她比的話我就□□□□了！」這段\n     文字的空格處，依序應填上哪一組成語？\n     (A)不分軒輊／望塵莫及／望其項背\n     (B)不分軒輊／望其項背／望塵莫及\n     (C)望其項背／望塵莫及／不分軒輊\n     (D)望其項背／不分軒輊／望塵莫及\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "下列四句話的文字與標點符號稍有差異，何者含意與其他三者相差最遠？", "options": ["哆啦A夢說他要帶大雄去暢遊未來世界。", "哆啦A夢說：「他要帶大雄去暢遊未來世界。」", "哆啦A夢說：「我要帶大雄去暢遊未來世界。」", "哆啦A夢告訴大雄：「我要帶你去暢遊未來世界。」"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7.   下列四句話的文字與標點符號稍有差異，何者含意與其他三者相差最遠？\n     (A)哆啦A夢說他要帶大雄去暢遊未來世界。\n     (B)哆啦A夢說：「他要帶大雄去暢遊未來世界。」\n     (C)哆啦A夢說：「我要帶大雄去暢遊未來世界。」\n     (D)哆啦A夢告訴大雄：「我要帶你去暢遊未來世界。」\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「 什麼東西都有它宿命注定的物主。想想在過去三千年中，此等周代鼎彝 1 曾\n經有過幾百個物主？沒有一個人在這個世界裡能永久享有一樣東西。眼前，我\n是它們的物主。再經過一百年，誰將是它們的物主呢？」這段文字的涵義，與\n下列何者最接近？", "options": ["天生萬物，人治萬物    ", "時移事易，物難久持    1.鼎彝：古代宗廟中的祭器。彝，音ㄧˊ", "君子當使物，不為物所使", "物各有所宜，用各有所施"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8.   「 什麼東西都有它宿命注定的物主。想想在過去三千年中，此等周代鼎彝 1 曾\n     經有過幾百個物主？沒有一個人在這個世界裡能永久享有一樣東西。眼前，我\n     是它們的物主。再經過一百年，誰將是它們的物主呢？」這段文字的涵義，與\n     下列何者最接近？\n     (A)天生萬物，人治萬物    \n     (B)時移事易，物難久持    1.鼎彝：古代宗廟中的祭器。彝，音ㄧˊ\n     (C)君子當使物，不為物所使\n     (D)物各有所宜，用各有所施\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「 會意」為合併兩個或兩個以上獨體的「文」，將它們的意思會聚起來，用以\n表現出新字含義的造字法則，如「森」字，由三個「木」構成，表示樹木繁\n多。據此判斷，下列何者也是「會意」字？", "options": ["鰻", "甘", "休", "鳥"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9.   「 會意」為合併兩個或兩個以上獨體的「文」，將它們的意思會聚起來，用以\n     表現出新字含義的造字法則，如「森」字，由三個「木」構成，表示樹木繁\n     多。據此判斷，下列何者也是「會意」字？\n     (A)鰻      (B)甘      (C)休     (D)鳥\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「君子如抱美玉而深藏不市，小人則以石為玉而又炫之。」根據這句話，君子\n不同於小人的特質是下列何者？", "options": ["臨財不苟", "真實坦率", "見多識廣", "沉潛含蓄"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. 「君子如抱美玉而深藏不市，小人則以石為玉而又炫之。」根據這句話，君子\n    不同於小人的特質是下列何者？\n    (A)臨財不苟  (B)真實坦率   (C)見多識廣  (D)沉潛含蓄\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "下列文句，何者語詞使用最恰當？", "options": ["這是我自己的人生，任憑誰能決定我的未來", "個性耿直的他，從小釐清志向要當一名檢察官", "這件事還是有轉圜的餘地，你何必這麼悲觀呢", "身為部會首長，他前往國會答覆民意代表的諮商"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 下列文句，何者語詞使用最恰當？\n    (A)這是我自己的人生，任憑誰能決定我的未來\n    (B)個性耿直的他，從小釐清志向要當一名檢察官\n    (C)這件事還是有轉圜的餘地，你何必這麼悲觀呢\n    (D)身為部會首長，他前往國會答覆民意代表的諮商\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「春天多細雨無聲，不走在雨中，不會有聽覺上的干擾。夏天的雨多如放聲嚎啕，\n傾盆而下，痛快淋漓，來得快，收得也快，不像冬天雨聲無休無止的纏繞。冬雨\n是可憐哀怨又於事無補的嘮叨，瑣碎卻不能有任何現況改善，最是煩人。」根據\n這段文字，下列敘述何者最恰當？", "options": ["春雨又細又輕，夏雨既急且驟", "冬雨滂沱，聲量最響，最為惱人", "夏天雨聲淒切，令人不由得加快行走的步伐", "走在冬雨中，常會聽到人們哀怨瑣碎的嘮叨"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 「春天多細雨無聲，不走在雨中，不會有聽覺上的干擾。夏天的雨多如放聲嚎啕，\n    傾盆而下，痛快淋漓，來得快，收得也快，不像冬天雨聲無休無止的纏繞。冬雨\n    是可憐哀怨又於事無補的嘮叨，瑣碎卻不能有任何現況改善，最是煩人。」根據\n    這段文字，下列敘述何者最恰當？\n    (A)春雨又細又輕，夏雨既急且驟\n    (B)冬雨滂沱，聲量最響，最為惱人\n    (C)夏天雨聲淒切，令人不由得加快行走的步伐\n    (D)走在冬雨中，常會聽到人們哀怨瑣碎的嘮叨\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "「當許多人把『氣候變遷』這幾個字，當成議題在世界上討論的時候，它其實\n已經成為再悲傷不過的語言了。」這句話的涵義，與下列何者最接近？", "options": ["「氣候變遷」被廣泛討論，代表它已造成威脅", "各國面對「氣候變遷」的議題時，應負起責任", "眾人已由空談「氣候變遷」轉為積極研擬對策", "討論「氣候變遷」這個議題，會使人變得悲觀"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 「當許多人把『氣候變遷』這幾個字，當成議題在世界上討論的時候，它其實\n    已經成為再悲傷不過的語言了。」這句話的涵義，與下列何者最接近？\n    (A)「氣候變遷」被廣泛討論，代表它已造成威脅\n    (B)各國面對「氣候變遷」的議題時，應負起責任\n    (C)眾人已由空談「氣候變遷」轉為積極研擬對策\n    (D)討論「氣候變遷」這個議題，會使人變得悲觀\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-105-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-105-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的詞語，何者使用最恰當？", "options": ["他發揮「全盤托出」的力量，盡力完成這項創舉", "今天聚會，敬呈拙作一本，請各位不吝「貽笑大方」", "孟母重視教育，帶著孟子「移樽就教」，搬到學校旁邊", "即使她非科班出身，但因表現優異，舞團決定「破格錄用」"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "9643cac0c05a", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 下列文句「」中的詞語，何者使用最恰當？\n    (A)他發揮「全盤托出」的力量，盡力完成這項創舉\n    (B)今天聚會，敬呈拙作一本，請各位不吝「貽笑大方」\n    (C)孟母重視教育，帶著孟子「移樽就教」，搬到學校旁邊\n    (D)即使她非科班出身，但因表現優異，舞團決定「破格錄用」\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
